const username = ($('Webhook (Get User Notes)').item.json.body.username || '').trim().toLowerCase();

const extractRichText = (prop) => {
  if (!prop) return '';
  if (typeof prop === 'string') return prop;
  if (Array.isArray(prop.rich_text)) {
    return prop.rich_text.map(r => r.plain_text || r.text?.content || '').join('');
  }
  if (Array.isArray(prop.title)) {
    return prop.title.map(r => r.plain_text || r.text?.content || '').join('');
  }
  return '';
};

const parseJsonSafely = (value, fallback) => {
  try {
    return JSON.parse(value);
  } catch {
    return fallback;
  }
};

const items = $input.all();

const results = items
  .filter(item => {
    const props = item.json.properties || {};
    const owner = extractRichText(props.Username).trim().toLowerCase();
    return owner === username;
  })
  .map(item => {
    const props = item.json.properties || {};
    const topic = extractRichText(props['Subject-name']) || 'Untitled';
    const notesRaw = extractRichText(props.Content);
    const flashcardsRaw = extractRichText(props.Flashcards);

    return {
      id: item.json.id,
      topic,
      username,
      createdTime: item.json.created_time,
      lastEditedTime: item.json.last_edited_time,
      notes: parseJsonSafely(notesRaw, notesRaw),
      flashcards: parseJsonSafely(flashcardsRaw, flashcardsRaw)
    };
  })
  .sort((a, b) => new Date(b.createdTime) - new Date(a.createdTime));

return [{ json: { username, items: results } }];
